    struct sysent *sysent_arr = (struct sysent *)resolve_kernel_symbol("_sysent");
    if (!sysent_arr) return KERN_FAILURE;

    lck_mtx_t *proc_list_lock = (lck_mtx_t *)resolve_kernel_symbol("_proc_list_lock");
    // ... use proc_list_lock as needed

    // Cast to function pointer for csops
    typedef int (*csops_func)(pid_t pid, unsigned int ops, void *useraddr, size_t usersize);
    csops_func csops_ptr = (csops_func)resolve_kernel_symbol("_csops");

